export interface LastUsedEditSettings extends SyncedEditSettings, UserPreferenceSettings {}

export const DEFAULT_LAST_USED: LastUsedEditSettings = {
  ...DEFAULT_SYNCED_SETTINGS,
  ...DEFAULT_USER_PREFERENCE_SETTINGS,
