    inpaintGenerateSuccess,
    isAnnotateMode,
    editMode,
    annotationMode,
    selectedShapeId,
    showTextModeHint,

    // Setters
    setIsInpaintMode,
    setInpaintPrompt,
    setInpaintNumGenerations,
    setBrushSize,
    setIsEraseMode,
    setIsAnnotateMode,
    setEditMode,
    setAnnotationMode,

    // Handlers
    handleEnterInpaintMode,
    handleUndo,
    handleClearMask,
    handleGenerateInpaint,
    handleGenerateAnnotatedEdit,
    handleDeleteSelected,
    handleToggleFreeForm,
    getDeleteButtonPosition,

    // StrokeOverlay callbacks
    onStrokeComplete,
    onStrokesChange,
    onSelectionChange,
    onTextModeHint,

    // Refs
    strokeOverlayRef,

    // Canvas state
    isImageLoaded,
    imageLoadError,
  };
};

